/*
 * BDWPCLS_impl.C -- WPS SOM method implementations for BDWPCLS
 *
 * This file contains the actual method bodies. The SOM dispatch stubs
 * (BDWPCLS.c) are generated by the 'sc' IDL compiler and must NOT
 * be edited -- compile them separately.
 *
 * Architecture:
 *   BDWPCLS is a WPProgram subclass that intercepts wpAddSettingsPages
 *   to insert a "Bidirectional Settings" notebook page into the Settings
 *   notebook of every DOS/WIN program object.
 *
 *   The bidi attributes are stored as instance data (flBidiAttr, idLang)
 *   and persisted via wpSaveState/wpRestoreState using wpSaveLong.
 *
 *   The settings dialog is implemented as a standard PM dialog (resource
 *   ID in BDWPCLS.DLL) and handles WM_INITDLG, WM_COMMAND, WM_CONTROL.
 *
 * Build (after running sc on BDWPCLS.idl):
 *   icc -c $(CFLAGS) $(DLLCFLAGS) -I. -Fo$(OBJDIR)\bdwpcls_impl.obj BDWPCLS_impl.c
 *   icc -c $(CFLAGS) $(DLLCFLAGS) -I. -Fo$(OBJDIR)\bdwpcls_sc.obj   BDWPCLS.c
 *   $(LINK) $(EXEDIR)\BDWPCLS.dll $(DLLCFLAGS) BDWPCLS.def \
 *       $(DLLLIBS) + $(SOMLIBS) \
 *       $(OBJDIR)\bdwpcls_impl.obj $(OBJDIR)\bdwpcls_sc.obj
 */

